    ("fan-dev","fan","review-aggregator","implementing"),
    ("fan-dev","fan","wishlist-manager","implementing"),
]

all_files = ["docs/agent_system_prompt.md","docs/task.md","docs/user_system_prompt.md",
             "evaluation/main.py","preprocess/main.py",
             "groundtruth_workspace/readme.txt","initial_workspace/readme.txt"]

for branch, dev, task, status in tasks:
    print(f"===== {task} ({status}) =====")
    base = f"https://raw.githubusercontent.com/hkustnlp-cmyk/BenchTasksCollv3/{branch}/tasks/{dev}/{task}/"
    for f in all_files:
        content = fetch(base+f)
        if content.startswith("<HTTP"):
            print(f"  {f:35s} {content}")
        else:
            has_cjk = bool(cjk_pattern.search(content))
            print(f"  {f:35s} len={len(content):4d} cjk={has_cjk}")
            if has_cjk:
                print("     >>>", repr(content))
    print()

